mapper.select:
SELECT cs.id, cs.fs_call_id AS fsCallId, cs.direction, cs.status, cs.customer_phone AS customerPhone, cs.customer_id AS customerId, cs.agent_id AS agentId, cs.skill_group_id AS skillGroupId, cs.create_time AS createTime, cs.end_time AS endTime, cs.duration_sec AS durationSec, cs.ended_by AS endedBy, cs.summary, cs.remark, c.name AS customerName, ap.agent_no AS agentName, (SELECT COUNT(*) FROM call_turn ct WHERE ct.session_id = cs.id AND ct.del_flag = 0) AS turnCount FROM call_session cs LEFT JOIN customer c ON c.id = cs.customer_id LEFT JOIN agent_profile ap ON ap.id = cs.agent_id
cs.del_flag = 0
AND cs.status = #{status}
AND cs.create_time BETWEEN #{startTime} AND #{endTime}
AND cs.create_time >= #{startTime}
AND cs.create_time <= #{endTime}
AND (cs.status != 'QUEUING' OR cs.agent_id IS NOT NULL)
ORDER BY cs.create_time DESC
